input.content:
@layer utilities {
  .booking-input:focus { box-shadow: 0 0 0 2px rgba(213,185,129,0.28); }
  .booking-select {
    background-image: url("data:image/svg+xml,%3Csvg...%3E");
    background-repeat: no-repeat;
    background-position: right 0.85rem center;
    background-size: 1rem;
    padding-right: 2.5rem;
  }
  .btn-gold-hover:hover:not(:disabled) {
    transform: translateY(-1px);
    box-shadow: 0 6px 24px rgba(213,185,129,0.3);
  }
  .btn-gold-hover:active:not(:disabled) {
    transform: translateY(0);
  }

  /* Animations */
  @keyframes modalFadeIn {
    from { opacity: 0; }
    to { opacity: 1; }
  }
  @keyframes modalScaleIn {
    from { transform: scale(0.9); }
    to { transform: scale(1); }
  }
  @keyframes slotGlow {
    0% { box-shadow: 0 0 0 0 rgba(213,185,129,0.4); }
    70% { box-shadow: 0 0 0 10px rgba(213,185,129,0); }
    100% { box-shadow: 0 0 0 0 rgba(213,185,129,0); }
  }

  /* Utilities */
  .backdrop-blur-sm { backdrop-filter: blur(4px); }
  .transition-smooth { transition: all 0.3s ease-out; }
  .error-state-border { border-color: #ff4d4d; }
  .success-state-border { border-color: #4caf50; }

  /* Fallbacks */
  .backdrop-blur-sm {
    background: rgba(0, 0, 0, 0.6);
    @supports (backdrop-filter: blur(4px)) {
      background: rgba(0, 0, 0, 0.4);
    }
  }

  /* Reduced motion */
  @media (prefers-reduced-motion: reduce) {
    .transition-smooth {
      transition: none;
    }
  }
}

import { useState, useEffect } from 'react';
import { X, AlertTriangle, CheckCircle } from 'lucide-react';

type BookingModalProps = {
  isOpen: boolean;
  onClose: () => void;
  onSubmit: (data: BookingData) => Promise<void>;
};

type BookingData = {
  branch: string;
  date: string;
  time: string;
  name: string;
  phone: string;
};

const BookingModal = ({ isOpen, onClose, onSubmit }: BookingModalProps) => {
  const [formData, setFormData] = useState<BookingData>({ branch: '', date: '', time: '', name: '', phone: '' });
  const [errors, setErrors] = useState<Partial<Record<keyof BookingData, string>>>({});  const [touched, setTouched] = useState<Partial<Record<keyof BookingData, boolean>>>({});  const [isLoading, setIsLoading] = useState(false);
  const [isSuccess, setIsSuccess] = useState(false);

  useEffect(() => {
    if (!isOpen) {
      setFormData({ branch: '', date: '', time: '', name: '', phone: '' });
      setErrors({});
      setTouched({});
      setIsSuccess(false);
    }
  }, [isOpen]);

  const handleChange = (e: React.ChangeEvent<HTMLInputElement | HTMLSelectElement>) => {
    const { name, value } = e.target;
    setFormData(prev => ({ ...prev, [name]: value }));
    if (touched[name as keyof BookingData]) {
      validateField(name as keyof BookingData, value);
    }
  };

  const validateField = (field: keyof BookingData, value: string) => {
    let error = '';
    if (!value.trim()) {
      error = 'Không được để trống';
    } else if (field === 'phone' && !/^\d{10}$/.test(value)) {
      error = 'Số điện thoại không hợp lệ';
    }
    setErrors(prev => ({ ...prev, [field]: error }));
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    const newErrors: Partial<Record<keyof BookingData, string>> = {};
    Object.keys(formData).forEach(key => {
      validateField(key as keyof BookingData, formData[key as keyof BookingData]);
    });
    if (Object.values(errors).some(error => error)) return;

    setIsLoading(true);
    try {
      await onSubmit(formData);
      setIsSuccess(true);
      setTimeout(() => {
        onClose();
        setIsSuccess(false);
      }, 2000);
    } catch (error) {
      alert('Đặt lịch thất bại, vui lòng thử lại');
    } finally {
      setIsLoading(false);
    }
  };

  if (!isOpen) return null;

  return (
    <div className="fixed inset-0 flex items-center justify-center z-50 data-[animation]:modalFadeIn data-[animation]:modalScaleIn">
      <div className="absolute inset-0 backdrop-blur-sm bg-black/60" onClick={onClose} />
      <div className="relative bg-gray-900 text-white p-8 rounded-lg w-full max-w-md mx-4 shadow-2xl">
        <button onClick={onClose} className="absolute top-4 right-4 text-gray-400 hover:text-white">
          <X size={24} />
        </button>
        <h2 className="text-2xl font-bold mb-6 text-center">Đặt Lịch Cắt Tóc</h2>
        {isSuccess ? (
          <div className="text-center text-green-500">
            <CheckCircle size={48} className="mx-auto mb-4" />
            <p>Đặt lịch thành công!</p>
          </div>
        ) : (
          <form onSubmit={handleSubmit} className="space-y-6">
            <FormFieldGroup
              label="Chi nhánh"
              name="branch"
              value={formData.branch}
              onChange={handleChange}
              error={errors.branch}
              touched={touched.branch}
              options={['Quận 1', 'Quận 3', 'Quận 7']}
            />
            <FormFieldGroup
              type="date"
              label="Ngày"
              name="date"
              value={formData.date}
              onChange={handleChange}
              error={errors.date}
              touched={touched.date}
            />
            <SlotSelector
              selectedTime={formData.time}
              onSelect={(time) => {
                setFormData(prev => ({ ...prev, time }));
                setTouched(prev => ({ ...prev, time: true }));
              }}
              error={errors.time}
            />
            <FormFieldGroup
              label="Họ và tên"
              name="name"
              value={formData.name}
              onChange={handleChange}
              error={errors.name}
              touched={touched.name}
            />
            <FormFieldGroup
              label="Số điện thoại"
              name="phone"
              value={formData.phone}
              onChange={handleChange}
              error={errors.phone}
              touched={touched.phone}
            />
            <BookingSummary formData={formData} />
            <button
              type="submit"
              disabled={isLoading}
              className="w-full btn-gold-hover py-3 rounded-lg text-lg font-semibold flex items-center justify-center"
            >
              {isLoading ? (
                <>
                  <svg className="animate-spin h-5 w-5 mr-3" viewBox="0 0 24 24">
                    <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4" />
                    <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z" />
                  </svg>
                  Đang xử lý...
                </> ) : 'Đặt lịch'}
            </button>
          </form> )} </div> </div> ); };

const FormFieldGroup = ({ label, name, value, onChange, error, touched, type = 'text', options }: any) => (
  <div className="relative">
    <label className="block text-sm font-medium mb-1" htmlFor={name}>{label}</label>
    {options ? (
      <select
        id={name}
        name={name}
        value={value}
        onChange={onChange}
        onBlur={() => setTouched(prev => ({ ...prev, [name]: true }))}
        className={`booking-select booking-input w-full px-4 py-3 rounded-lg bg-gray-800 border ${touched && error ? 'error-state-border' : 'border-gray-700'}`}
      >
        <option value="">Chọn {label.toLowerCase()}</option>
        {options.map((option: string) => (
          <option key={option} value={option}>{option}</option> ))} </select> ) : (
      <input
        type={type}
        id={name}
        name={name}
        value={value}
        onChange={onChange}
        onBlur={() => setTouched(prev => ({ ...prev, [name]: true }))}
        className={`booking-input w-full px-4 py-3 rounded-lg bg-gray-800 border ${touched && error ? 'error-state-border' : 'border-gray-700'}`}
      /> )} {touched && error && (
      <AlertTriangle size={20} className="text-red-500 absolute right-3 top-1/2 transform -translate-y-1/2" /> )} {touched && error && (
      <p className="text-red-500 text-sm mt-1">{error}</p> )} </div> );

const SlotSelector = ({ selectedTime, onSelect, error }: any) => (
  <div className="grid grid-cols-3 gap-3">
    {['9:00', '10:00', '11:00', '12:00', '13:00', '14:00', '15:00', '16:00', '17:00'].map(time => (
      <button
        key={time}
        type="button"
        onClick={() => onSelect(time)}
        className={`px-4 py-3 rounded-lg border ${selectedTime === time ? 'bg-gold-500 text-gray-900 border-gold-500 animate-slotGlow' : 'bg-gray-800 text-white border-gray-700 hover:bg-gray-700'} ${error ? 'error-state-border' : ''}`}
      >
        {time}
      </button> ))} </div> );

const BookingSummary = ({ formData }: any) => (
  <div className="bg-gray-800 p-4 rounded-lg">
    <h3 className="text-lg font-semibold mb-2">Thông tin đặt lịch</h3>
    <ul className="text-sm">
      <li>Chi nhánh: {formData.branch || 'Chưa chọn'}</li>
      <li>Ngày: {formData.date || 'Chưa chọn'}</li>
      <li>Giờ: {formData.time || 'Chưa chọn'}</li>
    </ul> </div> );

export default BookingModal;
